sql:
SELECT MIN(configuration_date) AS earliest_configuration_date, 
       MAX(configuration_date) AS latest_configuration_date
FROM robot_configuration;

SELECT robot_id, COUNT(*) AS data_point_count
FROM robot_movement_data
GROUP BY robot_id;

SELECT sensor_id, sensor_type 
FROM sensor 
WHERE description = 'Inertial Measurement Unit for tracking movement and orientation';

SELECT * 
FROM researcher 
WHERE researcher_id = 0;

SELECT COUNT(data_id) 
FROM robot_movement_data 
WHERE experiment_id = 0;

SELECT robot_id
FROM robot_movement_data
ORDER BY timestamp;

SELECT DISTINCT location_id 
FROM robot_movement_data 
ORDER BY location_id ASC;

SELECT frequency, EXP(frequency) AS ExponentialFrequency
FROM robot_movement_data
WHERE data_id = 1;

SELECT experiment.experiment_name, researcher.first_name, researcher.last_name
FROM experiment
INNER JOIN researcher ON experiment.researcher_id = researcher.researcher_id;

SELECT experiment_name 
FROM experiment 
WHERE researcher_id = 6001;

SELECT COUNT(*) 
FROM report 
WHERE researcher_id = 6001 AND generated_date > '2023-01-01';

external_knowledge:
- 'threshold of a gentle whisper' refers to an average amplitude greater than 0.5;
- 'grand symphony' is a metaphor for the experiment with ID 2001;
- 'names of the robots' refers to their respective robot IDs;
- 'decibel levels of their performance' refer to the average amplitude of the data they generated.

